mapper.insert:
INSERT INTO file_attachment (
    target_type, target_no, original_name, file_path, file_url, content_type, file_size
)
VALUES (
    #{targetType}, #{targetNo}, #{originalName}, #{filePath}, #{fileUrl}, #{contentType}, #{fileSize}
)

mapper.select:
SELECT attachment_no, target_type, target_no, original_name, file_path, file_url, content_type, file_size, created_at
FROM file_attachment
WHERE target_type = #{targetType}
  AND target_no = #{targetNo}
ORDER BY attachment_no DESC
